import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"郭沫若故居","description":"","frontmatter":{},"headers":[],"relativePath":"history/guo-moruo-residence.md","filePath":"history/guo-moruo-residence.md","lastUpdated":1784773307000}'),n={name:"history/guo-moruo-residence.md"};function d(o,t,s,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="郭沫若故居" tabindex="-1">郭沫若故居 <a class="header-anchor" href="#郭沫若故居" aria-label="Permalink to &quot;郭沫若故居&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-voV-byLj7qg?w=1200" alt="郭沫若故居"></p><blockquote><p>&quot;诗人、学者、革命家，一代文豪的京城岁月。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>郭沫若故居位于北京市西城区前海西街18号，是一座典型的北京四合院。郭沫若先生从1963年至1978年在此居住，度过了人生的最后15年。故居现已成为&quot;郭沫若纪念馆&quot;，展示着这位文学巨匠的生平事迹和珍贵文物。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周二至周日），周一闭馆</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-1.5小时</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区前海西街18号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="清代府邸" tabindex="-1">清代府邸 <a class="header-anchor" href="#清代府邸" aria-label="Permalink to &quot;清代府邸&quot;">​</a></h3><p>郭沫若故居原为清代恭王府的马号，后成为一座普通的四合院。1963年，郭沫若先生迁入此院。</p><h3 id="郭沫若晚年" tabindex="-1">郭沫若晚年 <a class="header-anchor" href="#郭沫若晚年" aria-label="Permalink to &quot;郭沫若晚年&quot;">​</a></h3><p>1963年至1978年，郭沫若先生在此居住，完成了大量重要的学术著作和文学作品。</p><h4 id="晚年成就" tabindex="-1">晚年成就 <a class="header-anchor" href="#晚年成就" aria-label="Permalink to &quot;晚年成就&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">成就</th></tr></thead><tbody><tr><td style="text-align:left;">1963年</td><td style="text-align:left;">迁入前海西街18号</td></tr><tr><td style="text-align:left;">1965年</td><td style="text-align:left;">创作《武则天》</td></tr><tr><td style="text-align:left;">1971年</td><td style="text-align:left;">创作《李白与杜甫》</td></tr><tr><td style="text-align:left;">1978年</td><td style="text-align:left;">逝世于此</td></tr></tbody></table><h2 id="故居布局" tabindex="-1">故居布局 <a class="header-anchor" href="#故居布局" aria-label="Permalink to &quot;故居布局&quot;">​</a></h2><h3 id="四合院结构" tabindex="-1">四合院结构 <a class="header-anchor" href="#四合院结构" aria-label="Permalink to &quot;四合院结构&quot;">​</a></h3><p>郭沫若故居是一座典型的北京四合院，分为外院和内院。</p><h4 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">建筑</th><th style="text-align:left;">功能</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大门</strong></td><td style="text-align:left;">入口</td><td style="text-align:left;">传统的朱漆大门</td></tr><tr><td style="text-align:left;"><strong>影壁</strong></td><td style="text-align:left;">照壁</td><td style="text-align:left;">精美的砖雕影壁</td></tr><tr><td style="text-align:left;"><strong>正房</strong></td><td style="text-align:left;">郭沫若居室</td><td style="text-align:left;">保留原貌</td></tr><tr><td style="text-align:left;"><strong>东厢房</strong></td><td style="text-align:left;">书房</td><td style="text-align:left;">郭沫若生前书房</td></tr><tr><td style="text-align:left;"><strong>西厢房</strong></td><td style="text-align:left;">展览室</td><td style="text-align:left;">生平事迹展</td></tr><tr><td style="text-align:left;"><strong>后院</strong></td><td style="text-align:left;">花园</td><td style="text-align:left;">郭沫若亲自设计</td></tr></tbody></table><h3 id="主要展室" tabindex="-1">主要展室 <a class="header-anchor" href="#主要展室" aria-label="Permalink to &quot;主要展室&quot;">​</a></h3><h4 id="正房展室" tabindex="-1">正房展室 <a class="header-anchor" href="#正房展室" aria-label="Permalink to &quot;正房展室&quot;">​</a></h4><p>正房是郭沫若先生的居室，保留了他生前的生活场景。</p><ul><li><strong>卧室</strong>：简朴的卧室，摆放着简朴的家具</li><li><strong>会客室</strong>：会客的地方，摆放着沙发和茶几</li><li><strong>工作室</strong>：郭沫若生前工作的地方</li></ul><h4 id="西厢房展室" tabindex="-1">西厢房展室 <a class="header-anchor" href="#西厢房展室" aria-label="Permalink to &quot;西厢房展室&quot;">​</a></h4><p>西厢房是郭沫若生平事迹展，展示了郭沫若先生一生的重要经历。</p><h4 id="东厢房展室" tabindex="-1">东厢房展室 <a class="header-anchor" href="#东厢房展室" aria-label="Permalink to &quot;东厢房展室&quot;">​</a></h4><p>东厢房是郭沫若的藏书室，收藏了大量珍贵书籍。</p><h2 id="珍贵文物" tabindex="-1">珍贵文物 <a class="header-anchor" href="#珍贵文物" aria-label="Permalink to &quot;珍贵文物&quot;">​</a></h2><h3 id="手稿和著作" tabindex="-1">手稿和著作 <a class="header-anchor" href="#手稿和著作" aria-label="Permalink to &quot;手稿和著作&quot;">​</a></h3><p>郭沫若故居收藏了大量郭沫若先生的手稿和著作。</p><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>手稿</strong></td><td style="text-align:left;">《武则天》《李白与杜甫》等手稿</td></tr><tr><td style="text-align:left;"><strong>著作</strong></td><td style="text-align:left;">各种版本的著作</td></tr><tr><td style="text-align:left;"><strong>书信</strong></td><td style="text-align:left;">与友人的往来书信</td></tr><tr><td style="text-align:left;"><strong>日记</strong></td><td style="text-align:left;">郭沫若的日记</td></tr></tbody></table><h3 id="生活用品" tabindex="-1">生活用品 <a class="header-anchor" href="#生活用品" aria-label="Permalink to &quot;生活用品&quot;">​</a></h3><p>郭沫若故居还保留了郭沫若先生生前使用的生活用品。</p><ul><li><strong>家具</strong>：简朴的木质家具</li><li><strong>文具</strong>：笔、墨、纸、砚</li><li><strong>藏书</strong>：大量珍贵藏书</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约1小时）</strong>：</p><p>入口 → 影壁 → 正房（郭沫若居室） → 东厢房（藏书室） → 西厢房（生平展） → 后院（花园） → 出口</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前预约</strong>：建议提前在官网或电话预约</li><li><strong>最佳时间</strong>：工作日人较少，适合慢慢参观</li><li><strong>拍照位置</strong>：影壁、正房前、后院都是绝佳拍照点</li><li><strong>讲解服务</strong>：可以租用讲解器，了解更多历史知识</li><li><strong>周边游览</strong>：参观完后可以到什刹海、恭王府游览</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">6号线北海北站B口，步行约5分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">13、42、107、111、118路北海北门站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;郭沫若故居&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京水乡</td></tr><tr><td style="text-align:left;">恭王府</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">清代王府</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">网红胡同</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>郭沫若是中国现代文学史上的重要人物，他的诗歌、戏剧、史学著作在中国文学史上占有重要地位。郭沫若故居不仅是一座名人故居，更是研究中国现代文学史的重要场所。</p><p>&quot;诗人、学者、革命家&quot;，这三个身份完美地概括了郭沫若先生的一生。</p><hr><p><strong>📍 地址</strong>：北京市西城区前海西街18号 ** 地铁**：6号线北海北站B口 <strong>📞 电话</strong>：010-83223327 <strong>🌐 官网</strong>：<a href="http://www.guomoruo.cn" target="_blank" rel="noreferrer">www.guomoruo.cn</a></p><p><strong>💡 Tips</strong>：郭沫若故居与恭王府相邻，可以安排在同一天参观。参观完后可以到什刹海散步，感受老北京的风情。</p>',50)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
